using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly List<Shipment> _shipments = GenerateSeedData();

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(
            s => s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
        {
            shipment.Status = newStatus;
        }
        return Task.CompletedTask;
    }

    private static List<Shipment> GenerateSeedData() =>
    [
        new()
        {
            Id = 1, TrackingNumber = "TRK-10001", Origin = "New York, US",
            Destination = "London, UK", Status = ShipmentStatus.InTransit,
            ShippedDate = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(4),
            CustomerEmail = "alice@example.com", Description = "Electronics - 2 boxes"
        },
        new()
        {
            Id = 2, TrackingNumber = "TRK-10002", Origin = "Shanghai, CN",
