            CustomerEmail = "bob@example.com", Description = "Furniture - 1 pallet"
        },
        new()
        {
            Id = 3, TrackingNumber = "TRK-10003", Origin = "Berlin, DE",
            Destination = "Tokyo, JP", Status = ShipmentStatus.OutForDelivery,
            ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow,
            CustomerEmail = "charlie@example.com", Description = "Auto parts - 5 crates"
        },
        new()
