            Id = 4, TrackingNumber = "TRK-10004", Origin = "São Paulo, BR",
            Destination = "Miami, US", Status = ShipmentStatus.Delayed,
            ShippedDate = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow.AddDays(2),
            CustomerEmail = "diana@example.com", Description = "Perishable goods - refrigerated"
        },
        new()
        {
            Id = 5, TrackingNumber = "TRK-10005", Origin = "Mumbai, IN",
            Destination = "Sydney, AU", Status = ShipmentStatus.Delivered,
            ShippedDate = DateTime.UtcNow.AddDays(-10), EstimatedDelivery = DateTime.UtcNow.AddDays(-1),
            CustomerEmail = "eve@example.com", Description = "Textiles - 3 bags"
        },
        new()
        {
            Id = 6, TrackingNumber = "TRK-10006", Origin = "Paris, FR",
            Destination = "Toronto, CA", Status = ShipmentStatus.Pending,
            ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(6),
            CustomerEmail = "frank@example.com", Description = "Cosmetics - 10 cartons"
        }
    ];
}

