@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<div class="container mt-4">
    <h2>🚚 Dispatcher Dashboard</h2>

    <div class="row mb-3">
        <div class="col-md-4">
            <label class="form-label">Filter by Status</label>
            <select class="form-select" @bind="selectedStatus">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
        <div class="col-md-4">
            <label class="form-label">Search Destination</label>
            <input type="text" class="form-control" placeholder="Type to filter..."
                   @bind="searchText" @bind:event="oninput" />
        </div>
    </div>

    @if (shipments is null)
    {
        <p><em>Loading shipments...</em></p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Status</th>
                        <th>Shipped</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var shipment in FilteredShipments)
                    {
                        <tr>
                            <td><strong>@shipment.TrackingNumber</strong></td>
                            <td>@shipment.Origin</td>
                            <td>@shipment.Destination</td>
                            <td>
                                <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                    @shipment.Status
                                </span>
                            </td>
                            <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                            <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                            <td>
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        @onchange="(e) => OnStatusChanged(shipment.Id, e)">
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@status" selected="@(status == shipment.Status)">@status</option>
                                    }
                                </select>
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
    }
</div>

@code {
    private List<Shipment>? shipments;
    private string selectedStatus = "";
    private string searchText = "";

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(selectedStatus) || s.Status.ToString() == selectedStatus)
            .Where(s => string.IsNullOrEmpty(searchText) ||
                        s.Destination.Contains(searchText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task OnStatusChanged(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateStatusAsync(id, newStatus);
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<div class="container mt-4">
    <h2>🔍 Track Your Shipment</h2>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-10001)"
                       @bind="trackingNumber" @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                    @if (isSearching)
                    {
                        <span class="spinner-border spinner-border-sm" role="status"></span>
                    }
                    else
                    {
                        <span>Track</span>
                    }
                </button>
            </div>
        </div>
    </div>

    @if (searched && shipment is null)
    {
        <div class="alert alert-warning">
            <strong>Not found.</strong> No shipment matches tracking number "<strong>@lastSearched</strong>".
            Please check and try again.
        </div>
    }

    @if (shipment is not null)
    {
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">@shipment.TrackingNumber</h5>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Description</dt>
                            <dd>@shipment.Description</dd>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Shipped Date</dt>
                            <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                            <dt>Estimated Delivery</dt>
                            <dd class="fs-5 fw-bold text-primary">
                                @shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")
                            </dd>
                        </dl>
                    </div>
                </div>

                <!-- Progress visualization -->
                <div class="mt-3">
                    <h6>Shipment Progress</h6>
                    <div class="progress" style="height: 25px;">
                        <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @(GetProgressPercent(shipment.Status))%"
                             aria-valuenow="@GetProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @shipment.Status
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string trackingNumber = "";
    private string lastSearched = "";
    private Shipment? shipment;
    private bool searched;
    private bool isSearching;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isSearching = true;
        lastSearched = trackingNumber.Trim();
        shipment = await ShipmentService.GetByTrackingNumberAsync(lastSearched);
        searched = true;
        isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await SearchShipment();
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}

