                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Description</dt>
                            <dd>@shipment.Description</dd>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Shipped Date</dt>
